const n = $('Normalisera inmatning').first().json;
const flow = items[0].json;
const raw = String(flow.text ?? flow.data?.text ?? flow.output ?? '');
const cleaned = raw.trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
let parsed = null;
try {
  parsed = cleaned ? JSON.parse(cleaned) : null;
} catch {}
const msg = String(n.message || '');
const lower = msg.toLowerCase();
const fallbackLeadType = /reportage|press|pr|influencer|partner|white label/.test(lower)
  ? 'press_or_partnership'
  : /fortfarande d[oö]d|r[oö]r sig inte|reklam|fel fisk|skadad/.test(lower)
    ? 'complaint_reroute'
    : /tidsmaskin/.test(lower)
      ? 'time_machine_interest'
      : /[aå]teruppliv|addon|till[aä]gg|upsell/.test(lower)
        ? 'addon_question'
        : /offert|volym|24|12|hotell|reception|kontor|butik|presentbox|avdelning/.test(lower)
          ? 'bulk_order'
          : 'unclear';
const fallbackCustomerType = /vi driver|vi (?:är|ar)|hotell|kontor|butik|team|avdelning|presentbox|upplevelsecenter|partner/.test(lower)
  ? 'B2B'
  : /^hej! jag|^hej jag|\bjag\b/.test(lower)
    ? 'Privatkund'
    : 'Oklart';
const fallbackProduct = /tidsmaskin/.test(lower)
  ? 'Tidsmaskin Experience Pack'
  : /[aå]teruppliv/.test(lower)
    ? 'Återupplivning Plus'
    : /m[aå]nadens|abonn/.test(lower)
      ? 'Månadens Mystiskt Orörliga Fisk'
      : 'Zombie Guppy Deluxe';
const fallbackPriority = /fortfarande d[oö]d|press|reportage|partner/.test(lower)
  ? 'high'
  : /volym|offert|hotell|kontor|upplevelsecenter/.test(lower)
    ? 'medium'
    : 'low';
items[0].json = {
  name: n.name,
  email: n.email,
  message: n.message,
  aiRaw: raw,
  aiSummary: String(parsed?.salesSummary || raw || ''),
  leadType: parsed?.leadType || fallbackLeadType,
  customerType: parsed?.customerType || fallbackCustomerType,
  productSuggestion: parsed?.productSuggestion || fallbackProduct,
  priority: parsed?.priority || fallbackPriority,
  routeTo: parsed?.routeTo || (fallbackLeadType === 'complaint_reroute' ? 'support' : 'sales'),
  funAngle: parsed?.funAngle || 'Bosses absurda affärsmodell gör leadet minnesvärt.',
  flowiseOk: Boolean(raw),
};
return items;

const full = String(items[0].json.name || '').trim();
const parts = full.split(/\s+/).filter(Boolean);
const firstName = parts[0] || 'Okänd';
const lastName = parts.length > 1 ? parts.slice(1).join(' ') : '-';
items[0].json.firstName = firstName;
items[0].json.lastName = lastName;
return items;

const prev = $('Klassificera intent (lead/support)').first().json;
const r = items[0].json;
const id = r.id || r.data?.id || r.record?.id || r.records?.[0]?.id;
if (!id) {
  throw new Error('Kunde inte läsa person-id från Twenty. Kontrollera TWENTY_API_KEY och REST-schema. Svar: ' + JSON.stringify(r).slice(0, 500));
}
items[0].json = {
  ...prev,
  personId: id,
};
return items;
